1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	};
7	
8	interface Item {
9	  type: string;
10	}
11	
12	interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	interface Scenario {
18	  customer: { yearsWithMHPCO: number };
19	  steps: QuoteStep[];
20	}
21	
22	export function runScenario(input: unknown): unknown {
23	  const scenario = input as Scenario;
24	  const results = scenario.steps.map((step) => {
25	    const base = step.items.reduce(
26	      (sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0),
27	      0,
28	    );
29	    const premium = base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE;
30	    return { premium };
31	  });
32	  return { results };
33	}
34

